// // This T flip-flop toggles the output on the falling edge of the clock when T is high, and resets asynchronously when the reset signal is deasserted.
module t_flip_flop (
    input wire clk,
    input wire rst_n,
    input wire t,
    output reg q
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            q <= 1'b0;
        end else if (t) begin
            q <= ~q;
        end
    end

endmodule
